CREATE TABLE IF NOT EXISTS `notifications` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `created_by` int(11) DEFAULT NULL COMMENT 'Admin who created this notification',
  `title` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `type` varchar(50) DEFAULT 'general' COMMENT 'login, registration, comment, etc',
  `data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Additional JSON payload' CHECK (json_valid(`data`)),
  `action_url` varchar(500) DEFAULT NULL COMMENT 'Action URL for notification',
  `is_read` tinyint(1) DEFAULT 0,
  `status` varchar(50) DEFAULT 'draft' COMMENT 'draft, sent, scheduled',
  `paused` tinyint(1) DEFAULT 0,
  `paused_at` datetime DEFAULT NULL,
  `pause_reason` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `sent_to_all_at` timestamp NULL DEFAULT NULL COMMENT 'When sent to all users',
  `scheduled_at` datetime DEFAULT NULL COMMENT 'Scheduled send time',
  `read_by_users` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'JSON array of user IDs who have read this notification' CHECK (json_valid(`read_by_users`)),
  `delivery_status` varchar(50) DEFAULT 'pending' COMMENT 'pending|in_progress|partially_sent|sent|failed (derived from notification_logs)',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_is_read` (`is_read`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_type` (`type`),
  KEY `idx_notifications_type` (`type`),
  KEY `idx_notifications_is_read` (`is_read`),
  KEY `idx_notifications_created_at` (`created_at`),
  KEY `idx_created_by` (`created_by`),
  KEY `idx_status` (`status`),
  CONSTRAINT `notifications_ibfk_created_by` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=227 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

